import argparse
import cmd
import csv
import time
from threading import Thread

import zmq

from rtSque import zmqports
from rtSque.loggers import StdOutPublisher, ZmqPublisher
from rtSque.rpc_client import RPCClientWrapper
from rtSque.rpc_server import RPCServerWrapper
from rtSque.tinyrpc.protocols import jsonrpc
import random


class DummyDispatcher(object):
    func_list = []
    default_ret = '6000'

    def __init__(self, publisher):
        self.publisher = publisher

    def dispatch(self, request):
        self.publisher.publish(request.serialize(), 'Dispatcher received request')
        self.func_list.append(request.method)
        time.sleep(0.05)  # slow down the response a bit to avoid flooding ZMQ queue
        if request.method == 'sleep':
            time.sleep(request.args[1])
            return request.respond(True)
        if request.method == jsonrpc.SERVER_READY:
            return request.respond('--PASS--')
        if request.method == 'long_test':
            time.sleep(5)
            return request.respond(True)
        if request.method == 'fixturetype':
            return request.respond('SIPFIXTURE')
        if request.method == 'station':
            return request.respond('COMBINE-FCT')
        if request.method == 'parse':
            return request.respond('dummy_parse_result')
        if request.method == 'getsn':
            return request.respond('YM1234567' + str(random.randint(10,99)))
        if request.method == 'measure':
            return request.respond(1.1101833258)
        if request.method == 'end_test':
            return request.respond('')
        if request.method == 'start_test':
            return request.respond('')
        if request.method == 'error':
            from rtSque.tinyrpc.protocols.jsonrpc import JSONRPCInvalidRequestError
            e = JSONRPCInvalidRequestError('fake error')
            return request.error_respond(e)
        if request.method == '::stop::':
            self.server.stop_server()  # this will stop the RPC server but console continues
        return request.respond(self.default_ret)


class ReplayDispatcher(object):
    def __init__(self, publisher, replay_file):
        self.publisher = publisher
        self.answers = []
        f = open(replay_file, 'r')
        reader = csv.DictReader(f)
        for row in reader:
            self.answers.append(row['Return'])
        f.close()

    def dispatch(self, request):
        if request.method != '::stop::':
            return request.respond(self.answers.pop())


class DummyTestEngine(Thread):

    def __init__(self, site, url):
        super(DummyTestEngine, self).__init__()
        self.site = site
        if 'tcp' in url:
        	self.url = 'tcp://*:'
        else:
        	self.url = url + ':'

        ctx = zmq.Context().instance()
        # Ensure subscriber connection has time to complete
        time.sleep(1)
        if site%10 == 0:
            self.publisher = ZmqPublisher(
                ctx,
                self.url + str(zmqports.TEST_ENGINE_PUB + int(site/10)),
                "DummyEngine_{}".format(site)
            )
            print ('DummyEngine-{} Pub on port {}'.format(site, str(zmqports.TEST_ENGINE_PUB + int(site/10))))
            time.sleep(0.5)  # give time for the subscribers to connect to this publisher
            self.wrapper = RPCServerWrapper(
                self.url + str(zmqports.TEST_ENGINE_PORT + int(site/10)),
                self.publisher,
                dispatcher=DummyDispatcher(self.publisher)
            )
            print ('DummyEngine-{} serves on port {}'.format(site, str(zmqports.TEST_ENGINE_PORT + int(site/10))))
        else:
            self.publisher = ZmqPublisher(
                ctx,
                self.url + str(zmqports.TEST_ENGINE_SUPP_PUB + site - 1),
                "DummyEngine_{}".format(site)
            )
            print ('DummyEngine-{} PUB on port {}'.format(site, str(zmqports.TEST_ENGINE_SUPP_PUB + site - 1)))
            time.sleep(0.5)  # give time for the subscribers to connect to this publisher
            self.wrapper = RPCServerWrapper(
                self.url + str(zmqports.TEST_ENGINE_SUPP_PORT + site - 1),
                self.publisher,
                dispatcher=DummyDispatcher(self.publisher)
            )
            print ('DummyEngine-{} serves on port {}'.format(site, str(zmqports.TEST_ENGINE_SUPP_PORT + site - 1)))

        self.rpc_server = self.wrapper.rpc_server
        self.wrapper.dispatcher.server = self.wrapper

    def run(self):
        self.publisher.publish('Test Engine {} Starting...'.format(self.site))
        self.rpc_server.start()
        self.publisher.publish('Test Engine {} Stopped...'.format(self.site))

def client_routine(site, url, method, params, timeout=1000):
    try:
        if 'tcp' in url:
            transport = 'tcp://localhost:'      
        else:
            trasnport = url + ':'

        client = RPCClientWrapper(
            trasnport + str(zmqports.TEST_ENGINE_PORT+site),
            StdOutPublisher('TE')
        ).remote_server()
        client.__getattr__(method)(params, timeout=timeout)
    except jsonrpc.RPCError as e:
        print (e)


def test_engine(site, url):
    te = DummyTestEngine(site, url)
    te.start()
    t1 = Thread(target=client_routine, args=(site, url, jsonrpc.SERVER_READY, None, 500))
    t1.start()
    t2 = Thread(target=client_routine, args=(site, url, 'short', None))
    t2.start()
    time.sleep(0.5)
    # if the server receives the stop request first, the other client will hang waiting for reply
    t3 = Thread(target=client_routine, args=(site, url, '::stop::', None))
    t3.start()

    time.sleep(0.1)
    t4 = Thread(target=client_routine, args=(site, url, 'test_retry', None))
    t4.start()

    t1.join()
    t2.join()
    t3.join()
    t4.join()
    te.join()


class EngineCLI(cmd.Cmd):
    prompt = 'test engine>'
    intro = 'Dummy Engine driver'

    def default(self, line):
        self.proxy.__getattr__(line)()

    def do_quit(self, line):
        self.proxy.__getattr__('::stop::')()
        return True


def start_client(site, transport):
    cli = EngineCLI()
    if 'tcp' in transport:
        url = 'tcp://localhost'
    else:
        url = transport
    cli.proxy = RPCClientWrapper(
        url + ':' + str(zmqports.TEST_ENGINE_PORT+site),
        StdOutPublisher('TEProxy')
    ).remote_server()

    cli.cmdloop()


def start_server(site, dimensions, transport, doreturn=True):
    for d in range(dimensions):
        sub_site = site*10 + d
        te = DummyTestEngine(sub_site, transport)
        te.start()
    if doreturn:
        return te


if __name__ == '__main__':
    parser = argparse.ArgumentParser()
    parser.add_argument('-t', '--test', help='run a test', action='store_true')
    parser.add_argument('-s', '--site', help='the site of the sequencer to connect to', type=int, default=0)
    parser.add_argument('-o', '--server_only', help='only start the server', action='store_true', default=False)
    parser.add_argument('-c', '--client_only', help='only start the client', action='store_true', default=False)
    parser.add_argument('-d', '--dimensions', help='number of dimensions', type=int, default=1)
    # parser.add_argument('-u', '--url', help='transport protocol', type=str, default='ipc:///tmp/.localhost')
    parser.add_argument('-u', '--url', help='transport protocol', type=str, default='tcp://127.0.0.1')


    args = parser.parse_args()

    if args.test:
        test_engine(args.site, args.url)
        exit()

    site = args.site
    if args.client_only:
        start_client(site, args.url)
        exit()
    if args.server_only:
        server = start_server(site, args.dimensions, args.url)
        server.join()
        exit()

    server = start_server(site, args.dimensions, args.url)
    time.sleep(1)
    start_client(site, args.url)

    server.join()
